import heapq

class Solution:
    def numberOfSets(self, n, maxDistance, roads):
        full_adj = [[] for _ in range(n)]
        for u, v, w in roads:
            full_adj[u].append((v, w))
            full_adj[v].append((u, w))
        total = 0
        for close_mask in range(1 << n):
            kept = [i for i in range(n) if not (close_mask >> i) & 1]
            if len(kept) <= 1:
                total += 1
                continue
            kept_set = set(kept)
            valid = True
            for src in kept:
                dist = {node: float('inf') for node in kept}
                dist[src] = 0
                visited = set()
                heap = [(0, src)]
                while heap:
                    d, u = heapq.heappop(heap)
                    if u in visited:
                        continue
                    visited.add(u)
                    for v, w in full_adj[u]:
                        if v not in kept_set:
                            continue
                        nd = d + w
                        if nd < dist[v]:
                            dist[v] = nd
                            heapq.heappush(heap, (nd, v))
                if any(dist[node] > maxDistance for node in kept):
                    valid = False
                    break
            if valid:
                total += 1
        return total

