class Solution:
    def numberOfSets(self, n, maxDistance, roads):
        count = 0
        for mask in range(1 << n):
            kept = [i for i in range(n) if not (mask >> i) & 1]
            if len(kept) <= 1:
                count += 1
                continue
            k = len(kept)
            idx = {node: i for i, node in enumerate(kept)}
            INF = float('inf')
            dist = [[INF] * k for _ in range(k)]
            for i in range(k):
                dist[i][i] = 0
            kept_set = set(kept)
            for u, v, w in roads:
                if u in kept_set and v in kept_set:
                    iu, iv = idx[u], idx[v]
                    if w < dist[iu][iv]:
                        dist[iu][iv] = w
                        dist[iv][iu] = w
            for m in range(k):
                for i in range(k):
                    if dist[i][m] == INF:
                        continue
                    for j in range(k):
                        nd = dist[i][m] + dist[m][j]
                        if nd < dist[i][j]:
                            dist[i][j] = nd
            ok = True
            for i in range(k):
                for j in range(k):
                    if dist[i][j] > maxDistance:
                        ok = False
                        break
                if not ok:
                    break
            if ok:
                count += 1
        return count

