var numberOfSets = function(n, maxDistance, roads) {
    let count = 0;
    for (let mask = 0; mask < (1 << n); mask++) {
        const kept = [];
        for (let i = 0; i < n; i++) {
            if (!((mask >> i) & 1)) kept.push(i);
        }
        if (kept.length <= 1) { count++; continue; }
        const k = kept.length;
        const idx = new Map();
        kept.forEach((node, i) => idx.set(node, i));
        const INF = Infinity;
        const dist = Array.from({ length: k }, () => new Array(k).fill(INF));
        for (let i = 0; i < k; i++) dist[i][i] = 0;
        const keptSet = new Set(kept);
        for (const [u, v, w] of roads) {
            if (keptSet.has(u) && keptSet.has(v)) {
                const iu = idx.get(u), iv = idx.get(v);
                if (w < dist[iu][iv]) {
                    dist[iu][iv] = w;
                    dist[iv][iu] = w;
                }
            }
        }
        for (let m = 0; m < k; m++) {
            for (let i = 0; i < k; i++) {
                if (dist[i][m] === INF) continue;
                for (let j = 0; j < k; j++) {
                    const nd = dist[i][m] + dist[m][j];
                    if (nd < dist[i][j]) dist[i][j] = nd;
                }
            }
        }
        let ok = true;
        outer:
        for (let i = 0; i < k; i++) {
            for (let j = 0; j < k; j++) {
                if (dist[i][j] > maxDistance) { ok = false; break outer; }
            }
        }
        if (ok) count++;
    }
    return count;
};
